import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../services/api';
import Cronometro from '../components/Cronometro';
import UploadFotos from '../components/UploadFotos';

function DetalhesOS() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [os, setOs] = useState(null);
  const [servicoRealizado, setServicoRealizado] = useState('');
  const [status, setStatus] = useState('');
  const [modalVisible, setModalVisible] = useState(false);
  const [modalMessage, setModalMessage] = useState('');
  const [modalCallback, setModalCallback] = useState(null);

  useEffect(() => {
    carregarOS();
  }, [id]);

  const carregarOS = async () => {
    try {
      const res = await api.get(`/os/${id}`);
      setOs(res.data);
      setServicoRealizado(res.data.servico_realizado || '');
      setStatus(res.data.status_os);
    } catch (err) {
      showModal('Erro ao carregar detalhes da OS', () => navigate('/'));
    }
  };

  const showModal = (message, onConfirm = null) => {
    setModalMessage(message);
    setModalCallback(() => onConfirm);
    setModalVisible(true);
  };

  const closeModal = () => {
    setModalVisible(false);
    if (modalCallback) modalCallback();
    setModalCallback(null);
  };

  const salvarAlteracoes = async () => {
    try {
      await api.put(`/os/${id}`, { servico_realizado: servicoRealizado, status_os: status });
      showModal('Alterações salvas com sucesso!', () => navigate('/'));
    } catch (err) {
      showModal('Erro ao salvar alterações');
    }
  };

  if (!os) return <div style={{ textAlign: 'center', marginTop: '50px' }}>Carregando...</div>;

  return (
    <div style={{ maxWidth: '1000px', margin: '0 auto', background: 'white', padding: '1.5rem', borderRadius: '16px', boxShadow: '0 4px 20px rgba(0,0,0,0.1)' }}>
      <h2 style={{ borderLeft: '5px solid #007bff', paddingLeft: '15px' }}>Detalhes da OS #{os.numero_os}</h2>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: '15px', margin: '20px 0' }}>
        <div><strong>Cliente:</strong> {os.cliente_nome}</div>
        <div><strong>Equipamento:</strong> {os.equipamento} {os.modelo}</div>
        <div><strong>IMEI:</strong> {os.imei || '—'}</div>
        <div><strong>Defeito relatado:</strong> {os.defeito}</div>
        <div><strong>Preço final:</strong> R$ {parseFloat(os.preco_final || 0).toFixed(2)}</div>
        <div><strong>Valor deslocamento:</strong> R$ {parseFloat(os.valor_deslocamento || 0).toFixed(2)}</div>
        <div><strong>Data abertura:</strong> {new Date(os.data_abertura).toLocaleDateString()}</div>
        <div><strong>Tipo atendimento:</strong> {os.tipo_atendimento === 'presencial' ? 'Presencial' : 'Remoto'}</div>
        <div><strong>Status:</strong> 
          <select value={status} onChange={e => setStatus(e.target.value)} style={{ marginLeft: '10px', padding: '4px', borderRadius: '4px' }}>
            <option value="aberto">Aberto</option>
            <option value="analise">Em análise</option>
            <option value="aguardando_peca">Aguardando peça</option>
            <option value="concluido">Concluído</option>
            {/* Removido "entregue" */}
          </select>
        </div>
      </div>

      <Cronometro osId={id} />
      <UploadFotos osId={id} />

      <div style={{ marginTop: '25px' }}>
        <label><strong>Serviço realizado (editável):</strong></label>
        <textarea rows="5" value={servicoRealizado} onChange={e => setServicoRealizado(e.target.value)} style={{ width: '100%', marginTop: '8px', padding: '10px', borderRadius: '8px', border: '1px solid #ccc' }} />
      </div>

      <div style={{ marginTop: '25px', display: 'flex', gap: '15px', flexWrap: 'wrap' }}>
        <button onClick={salvarAlteracoes} style={{ padding: '10px 20px', background: '#28a745', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer' }}>💾 Salvar e voltar</button>
        <button onClick={() => navigate('/')} style={{ padding: '10px 20px', background: '#6c757d', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer' }}>← Voltar sem salvar</button>
      </div>

      {/* Modal customizado */}
      {modalVisible && (
        <div style={{
          position: 'fixed',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          backgroundColor: 'rgba(0,0,0,0.5)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          zIndex: 2000
        }} onClick={closeModal}>
          <div style={{
            background: 'white',
            padding: '20px',
            borderRadius: '12px',
            minWidth: '250px',
            textAlign: 'center'
          }} onClick={e => e.stopPropagation()}>
            <p>{modalMessage}</p>
            <button onClick={closeModal} style={{ marginTop: '15px', padding: '6px 12px', background: '#007bff', color: 'white', border: 'none', borderRadius: '4px' }}>OK</button>
          </div>
        </div>
      )}
    </div>
  );
}

export default DetalhesOS;
